// Fake threshold: current tests only exercise "few cells die" vs. "block survives".
// Will be replaced with real neighbour-counting logic as more tests drive it out.
const MIN_CELLS_TO_SURVIVE = 3;

export function nextGeneration(liveCells: Cell[]): Cell[] {
  if (liveCells.length < MIN_CELLS_TO_SURVIVE) return [];
  return liveCells;
}
